        cohesion = sum(intra_scores) / len(intra_scores) if intra_scores else 0.0
        self._clusters[cluster_id] = ClusterRecord(
            cluster_id=cluster_id,
            entities=list(members),
            cohesion_score=round(cohesion, 4),
